1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PREMIUM = 60;
4	const DEDUCTIBLE = 100;
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	const INSURANCE_VALUES: Record<string, number> = Object.fromEntries(
16	  Object.entries(BASE_PREMIUMS).map(([type, premium]) => [type, premium * 10])
17	);
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	
21	function processClaim(
22	  step: any,
23	  policyStep: any,
24	  policyCumulativePayouts: Record<number, number>
25	): any {
26	  let insuranceSum = 0;
27	  for (const item of policyStep.items) {
28	    insuranceSum += INSURANCE_VALUES[item.type] || 0;
29	  }
30	  const cap = 2 * insuranceSum;
31	
32	  const insuredCounts: Record<string, number> = {};
33	  for (const item of policyStep.items) {
34	    insuredCounts[item.type] = (insuredCounts[item.type] || 0) + 1;
35	  }
36	
37	  const damageCounts: Record<string, number> = {};
38	  for (const damage of step.incident.damages) {
39	    damageCounts[damage.itemType] = (damageCounts[damage.itemType] || 0) + 1;
40	  }
41	
42	  for (const type of Object.keys(damageCounts)) {
43	    if (damageCounts[type] > (insuredCounts[type] || 0)) {
44	      throw new Error(`More damages of type ${type} than insured`);
45	    }
46	  }
47	
48	  for (const damage of step.incident.damages) {
49	    if (damage.amount < 0) {
50	      throw new Error("Negative damage amount");
51	    }
52	  }
53	
54	  let totalPayout = 0;
55	  for (const damage of step.incident.damages) {
56	    const matchedItem = policyStep.items.find((i: any) => i.type === damage.itemType);
57	    let reimbursement = damage.amount;
58	    if (matchedItem && matchedItem.enchantment >= 8) {
59	      reimbursement = damage.amount * 0.5;
60	    }
61	    totalPayout += reimbursement - DEDUCTIBLE;
62	  }
63	
64	  let payout = Math.floor(totalPayout);
65	  const previousPayouts = policyCumulativePayouts[step.policy] || 0;
66	  const remainingCap = cap - previousPayouts;
67	  if (payout > remainingCap) {
68	    payout = remainingCap;
69	  }
70	  policyCumulativePayouts[step.policy] = previousPayouts + payout;
71	
72	  return { payout, remainingCap: cap - policyCumulativePayouts[step.policy] };
73	}
74	
75	function processQuote(
76	  step: any,
77	  customer: any,
78	  isFollowUp: boolean
79	): any {
80	  const items = step.items;
81	
82	  const componentCounts: Record<string, number> = {};
83	  for (const item of items) {
84	    if (COMPONENT_TYPES.has(item.type)) {
85	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
86	    }
87	  }
88	
89	  let totalPremium = 0;
90	  let policyBasePremium = 0;
91	  const blocksApplied = new Set<string>();
92	
93	  for (const item of items) {
94	    if (!(item.type in BASE_PREMIUMS)) {
95	      throw new Error(`Unknown item type: ${item.type}`);
96	    }
97	    const isBlock = COMPONENT_TYPES.has(item.type) && componentCounts[item.type] === BLOCK_SIZE;
98	    if (isBlock && !blocksApplied.has(item.type)) {
99	      totalPremium += BLOCK_PREMIUM;
100	      policyBasePremium += BASE_PREMIUMS[item.type] * BLOCK_SIZE;
101	      blocksApplied.add(item.type);
102	    } else if (!isBlock) {
103	      let itemPremium = BASE_PREMIUMS[item.type];
104	      policyBasePremium += BASE_PREMIUMS[item.type];
105	      if (item.cursed) {
106	        itemPremium += BASE_PREMIUMS[item.type] * 0.5;
107	      }
108	      if (item.enchantment >= 5) {
109	        itemPremium += BASE_PREMIUMS[item.type] * 0.3;
110	      }
111	      totalPremium += itemPremium;
112	    }
113	  }
114	
115	  if (customer.yearsWithMHPCO >= 2) {
116	    totalPremium -= policyBasePremium * 0.2;
117	  }
118	
119	  totalPremium += policyBasePremium * 0.1;
120	
121	  if (isFollowUp) {
122	    totalPremium -= policyBasePremium * 0.15;
123	  }
124	
125	  return { premium: Math.ceil(totalPremium + PROCESSING_FEE) };
126	}
127	
128	export function claimOffice(request: any): any {
129	  const customer = request.customer;
130	  const results: any[] = [];
131	  const policyCumulativePayouts: Record<number, number> = {};
132	
133	  for (let stepIndex = 0; stepIndex < request.steps.length; stepIndex++) {
134	    const step = request.steps[stepIndex];
135	
136	    if (step.type === "claim") {
137	      const policyStep = request.steps[step.policy];
138	      results.push(processClaim(step, policyStep, policyCumulativePayouts));
139	    } else {
140	      results.push(processQuote(step, customer, stepIndex > 0));
141	    }
142	  }
143	
144	  return results;
145	}
